VALUES
  ('judicial-cf446b4c-moex-00194', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關緩刑，下列敘述何者正確？', '["緩刑期內因過失犯他罪，而在緩刑期內受逾6月有期徒刑之宣告確定者，應撤銷其緩刑宣告", "緩刑期內因故意犯他罪，而在緩刑期內受3月有期徒刑、拘役或罰金之宣告確定者，應撤銷其緩刑宣告", "緩刑之效力及於從刑，但不及於保安處分及沒收之宣告", "緩刑宣告，得斟酌情形，命犯罪行為人向被害人道歉、立悔過書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00195', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關假釋的規定，下列何者錯誤？', '["無期徒刑逾25年，始得聲請假釋", "須有悛悔實據", "有期徒刑執行已滿6個月始得聲請假釋", "未經撤銷假釋者，其未執行之刑，失其效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00196', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於犯罪追訴權時效，下列敘述何者錯誤？', '["刑法第320條第1項竊盜罪，因10年未起訴而追訴權消滅", "刑法第325條第1項搶奪罪，因20年未起訴而追訴權消滅", "刑法第328條第1項強盜罪，因30年未起訴而追訴權消滅", "刑法第339條之4第1項加重詐欺罪，因20年未起訴而追訴權消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00197', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者不是學說及實務上，所稱刑法上的「公務員」概念？', '["身分公務員", "學官公務員", "授權公務員", "委託公務員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00198', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲公務員對於違背職務之行為，要求、期約賄賂後，遭調離原單位。關於甲刑責，下列敘述何者正確？', '["甲不成立犯罪", "甲成立不違背職務收受賄賂罪", "甲成立違背職務期約賄賂罪", "甲分別觸犯違背職務期約賄賂與不違背職務收受賄賂二罪名，從一重處斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00199', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '於公務員依法執行職務時，實行下列何種行為，可能成立刑法第135條第1項之妨害公務罪？', '["向該公務員行賄", "向媒體誹謗該公務員", "向該公務員之長官陳情", "向該公務員施強暴脅迫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00200', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '受刑人甲經許可戒護就醫，在監所管理員乙戒護之下一同前往醫院，甲因思念小孩，遂拜託乙通融讓他回 家探視小孩，乙被甲說動，甲遂趁隙脫逃消失無蹤。有關甲、乙之刑責，下列敘述何者正確？', '["甲因無期待可能性，不成立犯罪", "甲成立刑法第161條第1項脫逃罪", "乙成立刑法第161條第1項脫逃罪之共同正犯", "乙成立刑法第161條第1項脫逃罪之幫助犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00201', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依通說與實務見解，下列何者非屬刑法第164條第1項所定「使之隱避」之行為？', '["對犯人提供偵查資訊使其容易掌握動向逃避", "對警察就犯人所在做虛偽陳述", "對犯人提供金錢或交通工具使其易於逃避偵查", "在詐欺犯罪集團第一次犯案前先提供自己帳戶、提款卡與密碼以便日後作人頭帳戶使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00202', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲代替酒後駕車的行為人乙出面，向警方自承是由他駕駛汽車，甲成立何罪？', '["誣告罪", "偽證罪", "頂替罪", "詐欺罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00203', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第168條偽證罪之規定，下列敘述何者正確？', '["鑑定人非本罪之行為主體", "證人未為具結，亦成立本罪", "證人於民事審判程序中所為之偽證行為，亦有偽證罪之適用", "證人於檢察官偵查時所為之偽證行為，不成立本罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
